@tool class_name RingDraw extends Node2D
## Width of the outer ring, in pixels. @export var ring_width := 4.0: set(v): ring_width = v queue_redraw() ## Radius of the circle, in pixels. @export var radius := 24.0: set(v): radius = v queue_redraw() ## Color of the outer ring. @export var ring_color := Color.WHITE: set(v): ring_color = v queue_redraw() ## Color of the inner circle. @export var fill_color := Color.TRANSPARENT: set(v): fill_color = v queue_redraw() ## Whether or not the circle should only render inside the editor, being invisible in game if true. @export var editor_only := false
func _draw() -> void: if editor_only and !Engine.is_editor_hint(): return if !is_zero_approx(ring_width): draw_circle(Vector2(), radius, ring_color, false, ring_width * 2) draw_circle(Vector2(), radius, fill_color)

@tool class_name Spline extends Path2D

@export var line: Line2D:
	set(v):
		line = v
		_update()
		update_configuration_warnings()
@export var point_count: int = 48:
	set(v):
		point_count = v
		_update()
@export_group("Start", "start_")
@export var start_progress: float:
	set(v):
		start_progress = v
		_update()
@export_range(0, 1) var start_prograss_ratio: float:
	set(v):
		start_progress = v * curve.get_baked_length()
	get:
		return start_progress / curve.get_baked_length()
@export_group("End", "end_")
@export var end_progress: float:
	set(v):
		end_progress = v
		_update()
@export_range(0, 1) var end_progress_ratio: float:
	set(v):
		end_progress = v * curve.get_baked_length()
	get:
		return end_progress / curve.get_baked_length()
var points: PackedVector2Array

func _get_configuration_warnings() -> PackedStringArray:
	if !line: return ["No Line2D node provided, so this node will not draw anything."]
	return []

func _process(delta: float) -> void:
	if points != curve.get_baked_points():
		points = curve.get_baked_points()
		_update()

func _update() -> void:
	if !line: return
	line.clear_points()
	if start_progress == end_progress: return
	if !curve.get_baked_points(): return
	for i in point_count:
		var offset := lerpf(start_progress, end_progress, float(i)/point_count)
		line.add_point(curve.sample_baked(offset))

@tool class_name PolygonOffsetter extends Polygon2D

@export var increase_amount: float = 7
@export_tool_button("Adjust polygon offset")
var _adjust := func() -> void:
	polygon = Geometry2D.offset_polygon(polygon, increase_amount, Geometry2D.JOIN_ROUND)[0]
